mapper.select:
select e.emp_id, e.emp_no, e.emp_name, d.dept_name, p.pos_name, 
e.emp_email, e.emp_mobile, e.emp_status, e.hire_date
from employee e join emp_position p on e.pos_id = p.pos_id
join department d on e.dept_id = d.dept_id


		and e.dept_id = #{deptId}


		and e.pos_id = #{posId}


		and e.emp_status = #{empStatus}


		and (e.emp_name like concat('%', #{keyword}, '%')
		or e.emp_no like concat('%', #{keyword}, '%'))


order by pos_order, emp_no
